"""
Config merger. Merges multiple config dicts with precedence rules.
"""
from dataclasses import dataclass, field
from typing import List


class MergeConflict(ValueError):
    """Raised when a type conflict is encountered in strict merge mode."""
    pass


class UnflattenConflict(TypeError):
    """Raised when flat keys conflict during unflattening (e.g. 'a' is both scalar and section)."""
    pass


@dataclass
class MergeReport:
    """Describes what deep_merge(base, override) would do, without modifying anything."""
    keys_added: List[str] = field(default_factory=list)
    keys_overridden: List[str] = field(default_factory=list)
    keys_removed: List[str] = field(default_factory=list)
    type_conflicts: List[str] = field(default_factory=list)


def deep_merge(base, override, path="", strategy="override"):
    """Merge override into base, returning a new dict.

    Rules:
    - Scalars: override wins (unless strategy changes this)
    - Dicts: recursive merge
    - Lists: concatenate (base + override)
    - None in override: removes the key from base

    Args:
        strategy: How to handle type conflicts (list vs scalar, dict vs scalar):
            - "override" (default): override always wins
            - "strict": raise MergeConflict on type mismatches
            - "append": when override is scalar and base is list, append scalar to list
            - "protect": base wins on conflicts (override ignored for conflicting keys)
    """
    result = dict(base)

    for key, value in override.items():
        if value is None:
            # None means "remove this key"
            result.pop(key, None)
            continue

        if key in result:
            base_val = result[key]
            full_path = f"{path}.{key}" if path else key

            if isinstance(base_val, dict) and isinstance(value, dict):
                # Both are dicts: recursive merge
                result[key] = deep_merge(base_val, value, full_path, strategy)

            elif isinstance(base_val, list) and isinstance(value, list):
                # Both are lists: concatenate
                result[key] = base_val + value

            elif isinstance(base_val, list) and not isinstance(value, list):
                # Type conflict: base is list, override is scalar
                if strategy == "strict":
                    raise MergeConflict(
                        f"Type conflict at '{full_path}': base is list, "
                        f"override is {type(value).__name__}"
                    )
                elif strategy == "append":
                    result[key] = base_val + [value]
                elif strategy == "protect":
                    pass  # base wins, leave result[key] unchanged
                else:  # "override"
                    result[key] = value

            elif isinstance(base_val, dict) and not isinstance(value, dict):
                # Type conflict: base is dict, override is scalar/list
                if strategy == "strict":
                    raise MergeConflict(
                        f"Type conflict at '{full_path}': base is dict, "
                        f"override is {type(value).__name__}"
                    )
                elif strategy == "protect":
                    pass  # base wins
                else:  # "override" or "append"
                    result[key] = value

            else:
                # Scalar vs scalar (or other non-structural cases)
                if strategy == "protect":
                    pass  # base wins
                else:
                    result[key] = value
        else:
            result[key] = value

    return result


def merge_report(base, override):
    """Return a MergeReport describing what deep_merge(base, override) would do.

    Does not modify base or override.
    """
    report = MergeReport()

    for key, value in override.items():
        if value is None:
            if key in base:
                report.keys_removed.append(key)
        elif key not in base:
            report.keys_added.append(key)
        else:
            base_val = base[key]
            if type(base_val) != type(value):
                report.type_conflicts.append(key)
            if base_val != value:
                report.keys_overridden.append(key)

    return report


def merge_configs(*configs):
    """Merge multiple configs with left-to-right precedence.

    First config is lowest priority, last is highest.

    Example:
        merge_configs(defaults, user_config, cli_overrides)
    """
    if not configs:
        return {}

    result = configs[0]
    for config in configs[1:]:
        result = deep_merge(result, config)

    return result


def flatten_config(config, prefix="", sep="."):
    """Flatten a nested config dict into dot-separated keys.

    Example:
        {"a": {"b": 1, "c": 2}} -> {"a.b": 1, "a.c": 2}
    """
    result = {}
    for key, value in config.items():
        full_key = f"{prefix}{sep}{key}" if prefix else key
        if isinstance(value, dict):
            result.update(flatten_config(value, full_key, sep))
        else:
            result[full_key] = value
    return result


def unflatten_config(flat_config, sep="."):
    """Unflatten dot-separated keys back into nested dict.

    Example:
        {"a.b": 1, "a.c": 2} -> {"a": {"b": 1, "c": 2}}

    Raises:
        UnflattenConflict: if a key is both a scalar value and a section prefix,
            e.g. {"a": 1, "a.b": 2}
    """
    result = {}
    for key, value in flat_config.items():
        parts = key.split(sep)
        target = result
        for part in parts[:-1]:
            if part not in target:
                target[part] = {}
            elif not isinstance(target[part], dict):
                raise UnflattenConflict(
                    f"Key conflict: '{part}' is both a scalar value and a section prefix"
                )
            target = target[part]
        target[parts[-1]] = value
    return result

"""Tests for merge strategies, merge_report, and unflatten_config conflict handling."""
import pytest
from src.merger import (
    deep_merge, merge_report, merge_configs,
    unflatten_config, MergeConflict, UnflattenConflict, MergeReport,
)


# ---------------------------------------------------------------------------
# strategy="override" (default)
# ---------------------------------------------------------------------------

class TestOverrideStrategy:
    def test_list_scalar_replaces(self):
        result = deep_merge({"tags": ["a", "b"]}, {"tags": "c"}, strategy="override")
        assert result == {"tags": "c"}

    def test_dict_scalar_replaces(self):
        result = deep_merge({"db": {"host": "localhost"}}, {"db": "sqlite"}, strategy="override")
        assert result == {"db": "sqlite"}

    def test_scalar_override(self):
        assert deep_merge({"a": 1}, {"a": 2}, strategy="override") == {"a": 2}

    def test_list_list_concat(self):
        result = deep_merge({"tags": ["a"]}, {"tags": ["b"]}, strategy="override")
        assert result == {"tags": ["a", "b"]}

    def test_default_is_override(self):
        # strategy="override" is the default
        result = deep_merge({"tags": ["a"]}, {"tags": "c"})
        assert result == {"tags": "c"}

    def test_new_key_added(self):
        assert deep_merge({"a": 1}, {"b": 2}) == {"a": 1, "b": 2}

    def test_none_removes(self):
        assert deep_merge({"a": 1, "b": 2}, {"a": None}) == {"b": 2}


# ---------------------------------------------------------------------------
# strategy="strict"
# ---------------------------------------------------------------------------

class TestStrictStrategy:
    def test_list_scalar_raises(self):
        with pytest.raises(MergeConflict, match="list"):
            deep_merge({"tags": ["a", "b"]}, {"tags": "c"}, strategy="strict")

    def test_dict_scalar_raises(self):
        with pytest.raises(MergeConflict, match="dict"):
            deep_merge({"db": {"host": "x"}}, {"db": "sqlite"}, strategy="strict")

    def test_error_includes_key_path(self):
        with pytest.raises(MergeConflict, match="tags"):
            deep_merge({"tags": ["a"]}, {"tags": "c"}, strategy="strict")

    def test_scalar_scalar_ok(self):
        assert deep_merge({"a": 1}, {"a": 2}, strategy="strict") == {"a": 2}

    def test_list_list_ok(self):
        result = deep_merge({"tags": ["a"]}, {"tags": ["b"]}, strategy="strict")
        assert result == {"tags": ["a", "b"]}

    def test_dict_dict_ok(self):
        result = deep_merge(
            {"db": {"host": "x"}}, {"db": {"port": 5432}}, strategy="strict"
        )
        assert result == {"db": {"host": "x", "port": 5432}}

    def test_nested_strict_conflict(self):
        with pytest.raises(MergeConflict):
            deep_merge(
                {"db": {"tags": ["a"]}},
                {"db": {"tags": "c"}},
                strategy="strict",
            )


# ---------------------------------------------------------------------------
# strategy="append"
# ---------------------------------------------------------------------------

class TestAppendStrategy:
    def test_list_scalar_appends(self):
        result = deep_merge({"tags": ["a", "b"]}, {"tags": "c"}, strategy="append")
        assert result == {"tags": ["a", "b", "c"]}

    def test_list_list_concatenates(self):
        result = deep_merge({"tags": ["a"]}, {"tags": ["b", "c"]}, strategy="append")
        assert result == {"tags": ["a", "b", "c"]}

    def test_scalar_scalar_override(self):
        assert deep_merge({"a": 1}, {"a": 2}, strategy="append") == {"a": 2}

    def test_dict_dict_merges(self):
        result = deep_merge(
            {"db": {"host": "x"}}, {"db": {"port": 5432}}, strategy="append"
        )
        assert result == {"db": {"host": "x", "port": 5432}}

    def test_append_single_item(self):
        result = deep_merge({"nums": [1, 2]}, {"nums": 3}, strategy="append")
        assert result == {"nums": [1, 2, 3]}


# ---------------------------------------------------------------------------
# strategy="protect"
# ---------------------------------------------------------------------------

class TestProtectStrategy:
    def test_list_scalar_keeps_base(self):
        result = deep_merge({"tags": ["a", "b"]}, {"tags": "c"}, strategy="protect")
        assert result == {"tags": ["a", "b"]}

    def test_dict_scalar_keeps_base(self):
        result = deep_merge({"db": {"host": "x"}}, {"db": "sqlite"}, strategy="protect")
        assert result == {"db": {"host": "x"}}

    def test_scalar_scalar_keeps_base(self):
        result = deep_merge({"a": 1}, {"a": 99}, strategy="protect")
        assert result == {"a": 1}

    def test_new_keys_added(self):
        result = deep_merge({"a": 1}, {"b": 2}, strategy="protect")
        assert result == {"a": 1, "b": 2}

    def test_nested_dict_protect(self):
        base = {"db": {"host": "x", "port": 5432}}
        override = {"db": {"port": 9999, "name": "mydb"}}
        result = deep_merge(base, override, strategy="protect")
        # port protected, new key "name" added
        assert result == {"db": {"host": "x", "port": 5432, "name": "mydb"}}

    def test_none_still_removes(self):
        # None/removal is not a conflict; it's an explicit deletion
        result = deep_merge({"a": 1, "b": 2}, {"a": None}, strategy="protect")
        assert result == {"b": 2}


# ---------------------------------------------------------------------------
# merge_report
# ---------------------------------------------------------------------------

class TestMergeReport:
    def test_returns_merge_report(self):
        assert isinstance(merge_report({}, {}), MergeReport)

    def test_keys_added(self):
        report = merge_report({"a": 1}, {"b": 2})
        assert report.keys_added == ["b"]
        assert report.keys_overridden == []

    def test_keys_overridden(self):
        report = merge_report({"a": 1}, {"a": 2})
        assert "a" in report.keys_overridden

    def test_keys_removed(self):
        report = merge_report({"a": 1, "b": 2}, {"a": None})
        assert report.keys_removed == ["a"]

    def test_type_conflict_list_scalar(self):
        report = merge_report({"tags": ["a", "b"]}, {"tags": "c"})
        assert "tags" in report.type_conflicts

    def test_type_conflict_dict_scalar(self):
        report = merge_report({"db": {"host": "x"}}, {"db": "sqlite"})
        assert "db" in report.type_conflicts

    def test_no_conflict_same_type(self):
        report = merge_report({"a": 1}, {"a": 2})
        assert report.type_conflicts == []

    def test_does_not_modify_base(self):
        base = {"a": 1}
        override = {"a": 2, "b": 3}
        merge_report(base, override)
        assert base == {"a": 1}

    def test_does_not_modify_override(self):
        base = {"a": 1}
        override = {"a": 2, "b": 3}
        merge_report(base, override)
        assert override == {"a": 2, "b": 3}

    def test_multiple_changes(self):
        base = {"a": 1, "b": [1, 2], "c": 3}
        override = {"a": 99, "b": "x", "d": 4, "c": None}
        report = merge_report(base, override)
        assert "a" in report.keys_overridden
        assert "b" in report.type_conflicts
        assert "d" in report.keys_added
        assert "c" in report.keys_removed

    def test_none_for_absent_key_not_removed(self):
        # None override on a key that doesn't exist in base → not a removal
        report = merge_report({}, {"a": None})
        assert report.keys_removed == []


# ---------------------------------------------------------------------------
# unflatten_config conflict handling
# ---------------------------------------------------------------------------

class TestUnflattenConflict:
    def test_raises_on_scalar_section_conflict(self):
        """{'a': 1, 'a.b': 2} should raise, not crash with TypeError."""
        with pytest.raises((TypeError, UnflattenConflict)):
            unflatten_config({"a": 1, "a.b": 2})

    def test_raises_unflatten_conflict_specifically(self):
        with pytest.raises(UnflattenConflict):
            unflatten_config({"a": 1, "a.b": 2})

    def test_error_message_is_descriptive(self):
        with pytest.raises(UnflattenConflict, match="conflict"):
            unflatten_config({"a": 1, "a.b": 2})

    def test_no_conflict_works_fine(self):
        result = unflatten_config({"a.b": 1, "a.c": 2})
        assert result == {"a": {"b": 1, "c": 2}}

    def test_deeper_conflict(self):
        with pytest.raises(UnflattenConflict):
            unflatten_config({"x.y": 1, "x.y.z": 2})
